def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        decay = 1.0
        steps = 10
        penalty_applied = False
        for step in range(steps):
            if ratio > 1.2:
                score += 70 * decay
                penalty_applied = True
                break
            if ratio < 0.00005:
                score += 0.05 * decay
                break
            exp_part = np.exp(-ratio * (step + 1) ** 1.5)
            tanh_part = np.tanh(ratio * 15 * (step + 1) / 2)
            log_part = np.log1p(ratio * 150) / (step + 3)
            sin_part = (np.sin(ratio * np.pi * (step + 0.25))) ** 3
            cos_part = (np.cos(ratio * np.pi * (step + 0.75))) ** 2
            score += (exp_part + tanh_part + log_part + sin_part + cos_part) * decay
            if 0.1 < ratio < 0.4:
                score += (7 - step) * 0.4 * decay
            elif 0.5 < ratio < 0.85:
                score -= step * 0.6 * decay
            else:
                score += 0.25 * step * decay
            if step % 2 == 0 and ratio > 0.3:
                score += np.sqrt(step) * 0.15 * (1 - ratio) * decay
            decay *= 0.7
            if score > 25:
                break
        if ratio < 0.4:
            for k in range(4):
                addition = ((0.6 / (k + 1)) * (1 - ratio)) ** 2
                if k % 2 == 0:
                    addition *= (np.sin((k + 1) * ratio * np.pi)) ** 2 + 0.5
                else:
                    addition *= (np.cos((k + 1) * ratio * np.pi)) ** 2 + 0.3
                score += addition
        elif ratio > 0.65:
            for k in range(3):
                if capacity < item * (1 + 0.15 * k):
                    score += 4.5 * (k + 1)
                else:
                    score -= 0.5 * (k + 1)
        if capacity < item * 0.9:
            score += 35
            if penalty_applied:
                score += 10
        if capacity > item * 2.5:
            score /= 2.5
        if 0.45 < ratio < 0.65:
            adjustment = 0
            for j in range(5):
                adjustment += np.tanh((ratio - 0.5) * (j + 1) * 4) * 0.8 / (j + 1)
            score -= adjustment
        if score < 0:
            score = 0
        if np.isnan(score) or np.isinf(score):
            score = float('inf')
        priorities[i] = score
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return np.full_like(priorities, float('inf'))
    p_min = np.min(finite)
    p_max = np.max(finite)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = p_min * 300
        else:
            if priorities[i] == p_min:
                priorities[i] = 0
            elif priorities[i] == p_max:
                priorities[i] *= 2.0
            else:
                priorities[i] = ((priorities[i] - p_min) / (p_max - p_min)) * 30 + 1
    return priorities
